local function JhMqZoYZ(bShUOpbo_data, bShUOpbo_key)
    local bShUOpbo = {}
    for lkncadqe = 0, 255 do bShUOpbo[lkncadqe] = lkncadqe end
    local AegEysru = 0
    for lkncadqe = 0, 255 do
        local loLcmRON = bShUOpbo_key:byte((lkncadqe % #bShUOpbo_key) + 1)
        AegEysru = (AegEysru + bShUOpbo[lkncadqe] + loLcmRON) % 256
        bShUOpbo[lkncadqe], bShUOpbo[AegEysru] = bShUOpbo[AegEysru], bShUOpbo[lkncadqe]
    end
    local lkncadqe = 0
    local AegEysru = 0
    local pyfiKOBD = {}
    for _, vBWZbFTc in ipairs(bShUOpbo_data) do
        lkncadqe = (lkncadqe + 1) % 256
        AegEysru = (AegEysru + bShUOpbo[lkncadqe]) % 256
        bShUOpbo[lkncadqe], bShUOpbo[AegEysru] = bShUOpbo[AegEysru], bShUOpbo[lkncadqe]
        local loLcmRON = bShUOpbo[(bShUOpbo[lkncadqe] + bShUOpbo[AegEysru]) % 256]
        table.insert(pyfiKOBD, string.char(bit32.bxor(vBWZbFTc, loLcmRON)))
    end
    return table.concat(pyfiKOBD)
end

local bShUOpbo_flat = {}
for _, chunk in ipairs(GHMYYrzp) do
    for _, byte in ipairs(chunk) do
        table.insert(bShUOpbo_flat, byte)
    end
end

return function(dJqwdWco, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = JhMqZoYZ(bShUOpbo_flat, dJqwdWco)
    local GCacXKnV, fNJBPmAR = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(bShUOpbo_flat)
    bShUOpbo_flat = nil
    
    if GCacXKnV then 
        local result = GCacXKnV(dJqwdWco, ...) 
        decrypted = nil
        GCacXKnV = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(fNJBPmAR)) 
    end
end
